-- Build member_risk_snapshots for all members with events
DO $$
DECLARE r RECORD;
BEGIN
  FOR r IN SELECT DISTINCT member_id FROM inference_events LOOP
    PERFORM upsert_member_risk_snapshot(r.member_id);
  END LOOP;
END $$;

-- Assign therapists to snapshots by org
UPDATE member_risk_snapshots s SET therapist_id = 'thr_001'
  FROM members m WHERE s.member_id = m.id
  AND m.org_id = 'org_univ_maryland' AND (m.id % 2) = 0;
UPDATE member_risk_snapshots s SET therapist_id = 'thr_002'
  FROM members m WHERE s.member_id = m.id
  AND m.org_id = 'org_univ_maryland' AND (m.id % 2) = 1;
